const fs = require('fs');
const path = require('path');
const packageJsonPath = path.join(process.cwd(), 'package.json');
const packageLockJsonPath = path.join(process.cwd(), 'package-lock.json');

// Read the package.json file and extract the dependencies
const packageJson = JSON.parse(fs.readFileSync(packageJsonPath));
const dependencies = Object.keys(packageJson.dependencies || {});

// Write the package-lock.json file with the extracted dependencies
fs.writeFileSync(packageLockJsonPath, JSON.stringify({ dependencies }, null, 2));